    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Policy: Stay in safe all-off state until both sensors have been seen validly. */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return output;
    }

    int level = controller->last_level;
    int temperature_c = controller->last_temperature_c;
    bool is_temperature_rising = (temperature_c > controller->previous_temperature_c);

    /* If either sensor becomes stale for more than 1000 ms, go to safe all-off. */
    if (controller->last_level_ms == 0U || controller->last_temperature_ms == 0U) {
        controller_set_safe_idle(controller);
        return output;
    }

    uint32_t elapsed_since_last_sensor = controller->last_level_ms > controller->last_temperature_ms ? 
                                          controller->last_level_ms : controller->last_temperature_ms;
    if (elapsed_since_last_sensor >= CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Check heater guard: If LEVEL < 55, keep HEATER OFF. */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        /* Low level: inlet open to fill, heater off */
        controller->inlet_open = true;
        controller->heater_on = false;
    } else {
        /* Safe level range check: 60 <= LEVEL <= 75 */
        bool in_safe_level_range = (level >= CONTROLLER_FILL_LEVEL_THRESHOLD && level <= CONTROLLER_LEVEL_HIGH_THRESHOLD);

        if (!in_safe_level_range) {
            /* Level too low or too high - close inlet and keep heater off */
            controller->inlet_open = false;
            controller->heater_on = false;
        } else {
            /* In safe level range: 60 <= LEVEL <= 75 */
            if (temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
                /* Low temperature in safe level range: INLET CLOSED and HEATER ON */
                controller->inlet_open = false;
                controller->heater_on = true;
            } else if (temperature_c >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                /* High temperature: INLET CLOSED and HEATER OFF */
                controller->inlet_open = false;
                controller->heater_on = false;
            } else if (temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temperature_c <= 48) {
                /* Near upper band: check if temperature is rising to turn heater off early */
                if (is_temperature_rising) {
                    /* Temperature rising in [47, 48]: HEATER OFF early */
                    controller->inlet_open = false;
                    controller->heater_on = false;
                } else {
                    /* Temperature not rising: hold previous safe heater state */
                    if (previous_heater_on) {
                        controller->heater_on = true;
                    }
                }
            } else {
                /* 45 <= TEMP < 47: INLET CLOSED and hold previous safe heater state */
                controller->inlet_open = false;
                if (previous_heater_on) {
                    controller->heater_on = true;
                }
            }
        }
    }

    /* Update state based on current output */
    if (controller->inlet_open && !controller->heater_on) {
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (!controller->inlet_open && controller->heater_on) {
        controller->state = CONTROLLER_STATE_HEATING;
    } else if (!controller->inlet_open && !controller->heater_on && 
               (level >= CONTROLLER_FILL_LEVEL_THRESHOLD && level <= CONTROLLER_LEVEL_HIGH_THRESHOLD)) {
        controller->state = CONTROLLER_STATE_HOLDING;
    } else {
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
    }

    /* Update sensor freshness based on input kind */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        return output;  /* Early return after applying timeout */
    case CONTROLLER_INPUT_NONE:
    default:
        controller_set_safe_idle(controller);
        return output;  /* Early return for no input */
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

